import{_ as e,o as r,c as t,a3 as l}from"./chunks/framework.q4B3G9ZH.js";const _=JSON.parse('{"title":"材质编译","description":"","frontmatter":{},"headers":[],"relativePath":"Unreal Engine/材质.md","filePath":"Unreal Engine/材质.md","lastUpdated":null}'),i={name:"Unreal Engine/材质.md"};function o(n,a,p,s,d,h){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="材质编译" tabindex="-1">材质编译 <a class="header-anchor" href="#材质编译" aria-label="Permalink to &quot;材质编译&quot;">​</a></h1><p>材质编译主要涉及以下几个概念类型：</p><ul><li><p><strong>UMaterialGraph</strong> UMaterialGraph是UMaterial的一个成员，用来存储编辑器产生的材质节点和参数。 UMaterialGraph主要记录了图形样式和图形节点(UEdGraphNode)。</p></li><li><p><strong>UMaterialGraphNode</strong> UMaterialGraphNode即我们在材质编辑器创建的材质节点，继承的父类依次是： UMaterialGraphNode→UMaterialGraphNode_Base→UEdGraphNode</p></li><li><p><strong>UMaterialExpression</strong> 就是表达式，每个材质节点(UMaterialGraphNode)上都有一个该类实例。</p></li><li><p><strong>FHLSLMaterialTranslator</strong> 作用是将材质的表达式转译成HLSL代码，填充到MaterialTemplate.ush的宏和空缺代码段。</p></li><li><p><strong>MaterialTemplate.ush</strong> MaterialTemplate.usf是材质shader模板，内涵大量%s的空缺和待替换的宏，它们由FHLSLMaterialTranslator::GetMaterialShaderCode负责填充。</p></li></ul><h2 id="材质编译流程" tabindex="-1">材质编译流程 <a class="header-anchor" href="#材质编译流程" aria-label="Permalink to &quot;材质编译流程&quot;">​</a></h2><p>材质ShaderMap的编译入口在FMaterial的以下两个接口：</p><ul><li>FMaterial::BeginCompileShaderMap</li><li>FMaterial::GetMaterialExpressionSource <strong>BeginCompileShaderMap</strong>主要分为几步： 初始化数据和新建编译对象，执行材质蓝图转译，如果转译成功，创建材质着色器编译环境，然后编译转译后的材质蓝图shader代码，最后会分为是否异步处理不同的返回ShaderMap，如果是同步直接返回，如果是异步则先放入到等待编译结束的列表OutstandingCompileShaderMapIds。</li></ul>',6)])])}const g=e(i,[["render",o]]);export{_ as __pageData,g as default};
